insert into public.modules (id,course_id,titulo,ordem) values ('5504c000-5011-4a00-9000-0000000000a2','8f29f6dd-3dc6-47fe-b4d3-1cd15514a21d','Mixagem ao Vivo',2)
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values
  ('5504c000-5011-4a00-9000-0000000000b2','5504c000-5011-4a00-9000-0000000000a2','Mixagem de show ao vivo: método, EQ por instrumento, grupos e monitores','texto','<p><strong>Mixar um show ao vivo é contar a história da música com o som.</strong> Não é deixar tudo alto — é dar a cada instrumento o seu lugar, com a voz na frente e uma base sólida, para que a plateia sinta a energia da banda. Nesta aula você aprende o método da mixagem ao vivo e, no simulador, mixa uma banda de verdade ouvindo cada ajuste.</p>
insert into public.quizzes (id,lesson_id,titulo) values ('5504c000-5011-4a00-9000-0000000000c2','5504c000-5011-4a00-9000-0000000000b2','Quiz — Mixagem de show ao vivo');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e1','5504c000-5011-4a00-9000-0000000000c2','Numa mixagem de show, o que deve ficar mais em evidência para a plateia?','A voz principal precisa estar clara e à frente; junto com uma base sólida de bumbo e baixo. A mix serve a música e à letra.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e1','Os pratos da bateria',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e1','A voz principal (com base sólida de bumbo e baixo)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e1','O teclado',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e1','Todos no mesmo volume máximo',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e2','5504c000-5011-4a00-9000-0000000000c2','Bumbo e baixo, juntos, formam o quê na mixagem?','A fundação (base) da mix — o peso e o groove. Acerte os dois juntos antes de subir o resto.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e2','O brilho da mix',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e2','A fundação/base da mix',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e2','O panorama estéreo',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e2','O retorno do palco',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e3','5504c000-5011-4a00-9000-0000000000c2','Para que serve um DCA (grupo)?','O DCA controla o volume de vários canais de uma vez (ex.: toda a bateria) sem alterar o equilíbrio entre eles.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e3','Controlar o volume de vários canais juntos, mantendo o equilíbrio interno',true,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e3','Adicionar reverb',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e3','Ligar o phantom',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e3','Trocar a frequência do sem fio',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e4','5504c000-5011-4a00-9000-0000000000c2','A mistura de AUX / monitor é:','É o que o músico ouve no palco (retorno/in-ear), diferente e independente da mix da plateia.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e4','A mesma coisa que a mix da plateia',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e4','A mistura que o músico ouve no palco (retorno)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e4','O volume do master',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e4','Um tipo de microfone',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e5','5504c000-5011-4a00-9000-0000000000c2','Jogar as guitarras uma para a esquerda e outra para a direita (pan) serve para:','Abrir o panorama estéreo — dar largura ao palco. Bumbo, baixo, caixa e voz normalmente ficam no centro.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e5','Aumentar o grave',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e5','Abrir o panorama estéreo (largura)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e5','Mutar as guitarras',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e5','Economizar canais',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e6','5504c000-5011-4a00-9000-0000000000c2','Para que serve o SOLO de um canal?','Isolar um canal para ouvi-lo sozinho e ajustar/achar um problema, sem a distração do resto da mix.',6,1);
