insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e6','Ouvir um canal isolado para ajustar/conferir',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e6','Aumentar o master',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e6','Gravar o canal',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e7','5504c000-5011-4a00-9000-0000000000c2','Por que ligar o HPF na voz e nas guitarras?','Para tirar os graves desnecessários dessas fontes, limpando a mix e deixando espaço para bumbo e baixo.',7,1);
