insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e7','Para tirar graves desnecessários e limpar a mix',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e7','Para aumentar o volume',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e7','Para ligar o compressor',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5504c000-5011-4a00-9000-0000000000e8','5504c000-5011-4a00-9000-0000000000c2','Qual a melhor ordem para construir a mixagem?','Base (bumbo e baixo) → resto da bateria → instrumentos harmônicos → voz por cima de tudo.',8,1);
