insert into public.quiz_options (question_id,texto,correta,ordem) values ('5504c000-5011-4a00-9000-0000000000e8','Pratos → guitarras → bumbo',false,4);
insert into public.ai_animations (lesson_id,tipo,status,model,custo_usd,roteiro,urls) values ('5504c000-5011-4a00-9000-0000000000b2','interactive','ready','handcrafted-interactive',0,'{"titulo":"Simulador — Mixagem de Show ao Vivo","cenas":[{"numero":1,"titulo":"Mixe a banda (áudio real)","modo":"widget","narracao":"Mixe uma banda ao vivo ouvindo em tempo real: faders, EQ, HPF, compressor, pan, DCA e solo/mute. Complete as missões.","explicacao_texto":"Simulador de mixagem com áudio (placeholder — será trocado pelas músicas reais da SMU). Todas as funções da mesa.","destaques":["Canais nomeados por instrumento","EQ de 3 bandas por canal","Grupos/DCA e master","Monitores (AUX), solo e mute"]}]}'::jsonb,'[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Mixagem de Show (Rock/Samba/Pagode/Pagodão) — SMU</title>\n<style>\n  :root{--bg:#0b0f17;--panel:#141b29;--panel2:#0e1420;--line:#26344c;--ink:#e7ecf5;\n    --muted:#8ea0bd;--amber:#F59E0B;--green:#22c55e;--red:#ef4444;--cyan:#22d3ee;--strip:#111a29}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:6px;user-select:none;overflow-x:hidden;\n    min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center}\n  .fit{width:max-content;flex:0 0 auto}\n  .fit .board{overflow:visible}\n  @media(max-width:760px){ body{justify-content:flex-start;align-items:stretch} .fit{width:100%} .fit .board{overflow-x:auto} }\n  /* iOS/iPad: trava o pan (arraste não vira gesto de sair da tela cheia) em tablet/desktop */\n  @media(min-width:760px){ body,.fit{touch-action:none} }\n  h1{font-size:15px;margin:0 0 2px}.sub{font-size:11px;color:var(--muted);margin-bottom:8px}\n  .top{display:flex;gap:9px;align-items:center;background:linear-gradient(180deg,#141c2c,#0f1523);border:1px solid var(--line);border-radius:10px;padding:8px 12px;margin-bottom:8px;flex-wrap:wrap}\n  .play{font:inherit;font-size:13px;font-weight:800;padding:9px 16px;border-radius:9px;border:0;background:var(--green);color:#08120a;cursor:pointer}\n  .play.stop{background:var(--red);color:#fff}\n  .genres{display:flex;gap:5px;flex-wrap:wrap}\n  .gbtn{font:inherit;font-size:11.5px;font-weight:700;padding:8px 12px;border-radius:8px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .gbtn.on{background:var(--amber);border-color:var(--amber);color:#0b0f17}\n  .pill{font-size:10px;color:var(--muted);background:#0c1220;border:1px solid var(--line);border-radius:20px;padding:5px 9px}\n  .mmeter{display:flex;gap:4px;align-items:center}.mmeter .bar{width:60px;height:9px;border-radius:5px;background:#05070d;border:1px solid #1a2540;overflow:hidden}\n  .mmeter .bar i{display:block;height:100%;width:0%;background:linear-gradient(90deg,var(--green),var(--amber) 82%,var(--red))}\n  .spacer{flex:1}\n  .mission{display:flex;gap:9px;align-items:center;background:#0c1220;border:1px solid var(--line);border-radius:9px;padding:7px 10px;max-width:100%;flex-basis:100%}\n  .mission .idx{font-size:9.5px;color:var(--amber);font-weight:800;white-space:nowrap}\n  .mission .txt{font-size:11.5px;line-height:1.25;flex:1}.mission .txt b{color:var(--amber)}\n  .mission button{font:inherit;font-size:10px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:6px;padding:5px 7px;cursor:pointer}\n\n  .selpanel{display:none;background:linear-gradient(180deg,#141c2c,#0e1420);border:1px solid var(--amber);border-radius:11px;padding:10px;margin-bottom:8px}\n  .selpanel.show{display:flex;gap:12px;flex-wrap:wrap}\n  .selpanel .eqbox{flex:1 1 420px;min-width:280px}\n  .selhead{display:flex;align-items:center;gap:8px;margin-bottom:6px}\n  .selhead .chip{width:10px;height:22px;border-radius:3px}.selhead .nm{font-size:14px;font-weight:800}\n  .selhead .close{margin-left:auto;font:inherit;font-size:11px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:7px;padding:5px 9px;cursor:pointer}\n  #eqcanvas{width:100%;height:170px;background:#080d15;border:1px solid #1b2740;border-radius:9px;display:block;touch-action:none}\n  .dynbox{flex:1 1 240px;display:flex;flex-direction:column;gap:8px}\n  .dynrow{display:flex;gap:8px;align-items:center}\n  .dynrow label{font-size:11px;color:var(--muted);width:78px}\n  .dynrow input[type=range]{flex:1;accent-color:var(--amber);height:22px}\n  .dynrow .v{font-size:11px;font-weight:700;width:52px;text-align:right}\n  .tgs{display:flex;gap:6px;flex-wrap:wrap}\n  .tg{font:inherit;font-size:10.5px;font-weight:800;padding:7px 10px;border-radius:8px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .tg.on{background:var(--green);border-color:var(--green);color:#08120a}.tg.on.amber{background:var(--amber);border-color:var(--amber);color:#0b0f17}\n\n  .board{display:flex;gap:6px;overflow-x:auto;padding:8px;background:linear-gradient(180deg,#0e1420,#0a0f18);border:1px solid var(--line);border-radius:12px}\n  .strip{flex:0 0 90px;background:linear-gradient(180deg,var(--strip),#0e1524);border:1px solid var(--line);border-radius:9px;padding:6px 5px;display:flex;flex-direction:column;align-items:center;gap:5px}\n  .strip.sel{border-color:var(--amber);box-shadow:0 0 0 1px var(--amber) inset}\n  .strip.fx{flex-basis:86px;background:linear-gradient(180deg,#1a1430,#0e1524);border-color:#5b3aa0}\n  .strip.dca{flex-basis:76px;background:linear-gradient(180deg,#1a2233,#0e1524);border-color:#3a4d70}\n  .strip.master{flex-basis:86px;background:linear-gradient(180deg,#241d10,#0e1524);border-color:var(--amber)}\n  .cname{width:100%;border-radius:4px;color:#0b0f17;font-size:9px;font-weight:800;text-align:center;padding:2px 1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n  .knob{display:flex;flex-direction:column;align-items:center;gap:1px}\n  .dial{width:26px;height:26px;border-radius:50%;position:relative;cursor:ns-resize;touch-action:none;background:radial-gradient(circle at 50% 32%,#33415f,#151d2e 72%);border:1px solid #3a4d70}\n  .dial::after{content:\"\";position:absolute;left:50%;top:3px;width:2px;height:9px;border-radius:2px;background:var(--amber);transform-origin:50% 11px;transform:translateX(-50%) rotate(var(--rot,0deg))}\n  .dial.eq::after{background:var(--cyan)}.dial.g::after{background:#fff}.dial.fx::after{background:#a855f7}\n  .kl{font-size:7px;color:var(--muted)}\n  .rowk{display:flex;gap:3px}\n  .mini{font:inherit;font-size:8px;font-weight:800;padding:3px 0;width:100%;border-radius:5px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .mini.sel.on{background:var(--amber);border-color:var(--amber);color:#0b0f17}\n  .faderwrap{display:flex;gap:4px;height:100px;align-items:stretch}\n  .meter{width:6px;border-radius:3px;background:#05070d;border:1px solid #1a2540;position:relative;overflow:hidden}\n  .meter i{position:absolute;left:0;right:0;bottom:0;height:0%;background:linear-gradient(0deg,var(--green),var(--green) 60%,var(--amber) 84%,var(--red))}\n  .fader{width:22px;position:relative;background:linear-gradient(90deg,#0a0e17,#0d1220,#0a0e17);border-radius:5px;border:1px solid #1a2540;cursor:ns-resize;touch-action:none}\n  .fader .u{position:absolute;left:0;right:0;top:22%;height:1px;background:#3a4d70}\n  .cap{position:absolute;left:-4px;right:-4px;height:16px;border-radius:4px;background:linear-gradient(180deg,#e9edf5,#a7b3c9 46%,#59647e 54%,#8493ad);border:1px solid #0006;cursor:grab}\n  .cap::after{content:\"\";position:absolute;left:3px;right:3px;top:50%;height:2px;transform:translateY(-50%);background:#0b0f17;border-radius:2px}\n  .fdb{font-size:8px;color:var(--muted);font-weight:700}\n  .btnrow{display:flex;gap:3px;width:100%}\n  .sb{flex:1;font:inherit;font-size:8px;font-weight:800;padding:4px 0;border-radius:5px;border:1px solid var(--line);background:#0c1220;color:var(--muted);cursor:pointer}\n  .sb.solo.on{background:var(--amber);border-color:var(--amber);color:#0b0f17}.sb.mute.on{background:var(--red);border-color:var(--red);color:#fff}\n  .assign{font-size:6.5px;color:var(--muted);text-align:center;line-height:1}\n  .hint{font-size:10px;color:var(--muted);margin-top:8px;text-align:center}\n  .toast{position:fixed;left:50%;bottom:14px;transform:translateX(-50%) translateY(20px);background:#0c1220;border:1px solid var(--amber);color:var(--ink);padding:9px 15px;border-radius:9px;font-size:12px;opacity:0;transition:.25s;pointer-events:none;z-index:50}\n  .toast.show{opacity:1;transform:translateX(-50%) translateY(0)}.toast b{color:var(--amber)}\n</style>\n</head>\n<body>\n <div class=\"fit\">\n  <h1>Mixagem de Show — treino por gênero</h1>\n  <div class=\"sub\">Escolha o ritmo e mixe a banda: gain, EQ paramétrico, dinâmica, efeitos, grupos, pan, solo/mute e master.</div>\n  <div class=\"top\">\n    <button class=\"play\" id=\"play\">▶ Tocar</button>\n    <div class=\"genres\" id=\"genres\"></div>\n    <span class=\"pill\" id=\"srcTag\">áudio: placeholder (troca pelos stems reais)</span>\n    <span class=\"mmeter\"><span style=\"font-size:10px;color:var(--muted)\">MASTER</span><span class=\"bar\"><i id=\"mainMeter\"></i></span></span>\n    <div class=\"spacer\"></div>\n    <div class=\"mission\"><span class=\"idx\" id=\"mIdx\">MISSÃO</span><span class=\"txt\" id=\"mTxt\">—</span><button id=\"mSkip\">Pular</button></div>\n  </div>\n\n  <div class=\"selpanel\" id=\"selpanel\">\n    <div class=\"eqbox\">\n      <div class=\"selhead\"><span class=\"chip\" id=\"selChip\"></span><span class=\"nm\" id=\"selName\">—</span>\n        <span style=\"font-size:10px;color:var(--muted)\">EQ paramétrico — arraste as bolinhas (freq × ganho)</span>\n        <button class=\"close\" id=\"selClose\">Fechar ✕</button></div>\n      <canvas id=\"eqcanvas\"></canvas>\n    </div>\n    <div class=\"dynbox\">\n      <div class=\"tgs\"><button class=\"tg\" id=\"tHpf\">HPF</button><button class=\"tg\" id=\"tGate\">GATE</button><button class=\"tg\" id=\"tComp\">COMP</button></div>\n      <div class=\"dynrow\"><label>Gain (trim)</label><input type=\"range\" id=\"sGain\" min=\"-12\" max=\"24\" step=\"1\" value=\"0\"><span class=\"v\" id=\"vGain\">0 dB</span></div>\n      <div class=\"dynrow\"><label>Gate thr</label><input type=\"range\" id=\"sGate\" min=\"-70\" max=\"0\" step=\"1\" value=\"-40\"><span class=\"v\" id=\"vGate\">-40</span></div>\n      <div class=\"dynrow\"><label>Comp thr</label><input type=\"range\" id=\"sComp\" min=\"-40\" max=\"0\" step=\"1\" value=\"-24\"><span class=\"v\" id=\"vComp\">-24</span></div>\n      <div class=\"dynrow\"><label>Reverb</label><input type=\"range\" id=\"sRev\" min=\"0\" max=\"100\" step=\"1\" value=\"0\"><span class=\"v\" id=\"vRev\">0</span></div>\n      <div class=\"dynrow\"><label>Delay</label><input type=\"range\" id=\"sDly\" min=\"0\" max=\"100\" step=\"1\" value=\"0\"><span class=\"v\" id=\"vDly\">0</span></div>\n    </div>\n  </div>\n\n  <div class=\"board\" id=\"board\"></div>\n  <div class=\"hint\">Aperte <b>SEL</b> num canal para o EQ paramétrico e a dinâmica. Role a mesa para ver FX, grupos e master. Funciona no celular.</div>\n </div>\n  <div class=\"toast\" id=\"toast\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  const dbToLin=db=>Math.pow(10,db/20);\n  // canal: [id,nome,cor,dcaIndex,familia,params,fader,pan,hpfOn,comp,pat16]\n  function ch(id,nm,color,dca,fam,p,fader,pan,hpf,cmp,pat){return {id,nm,color,dca,fam,p,gain:0,fader,pan,hpfOn:hpf,cmp,gateOn:false,gateThr:-40,compThr:-24,rev:0,dly:0,mute:false,solo:false,pat,\n    eq:{hpfOn:hpf,hpf:90,low:{f:110,g:0},loMid:{f:450,g:0,q:1},hiMid:{f:2500,g:0,q:1},high:{f:7000,g:0}}};}\n  const X=(...a)=>[0,0,0,0,