orecordarreal:{label:\"🎵 Forró Pra Recordar REAL (c/ voz)\", real:true, folder:\"mix-forro-recordar\",\n      dca:[{nm:\"Percussão\",color:\"#f59e0b\"},{nm:\"Banda\",color:\"#22d3ee\"},{nm:\"Vozes\",color:\"#a855f7\"}], ch:()=>[\n      chR(\"bb\",\"Bumbo\",\"#ef4444\",0,\"1-BB.mp3\",66,0,false,false),\n      chR(\"cx\",\"Caixa\",\"#f97316\",0,\"2-CX.mp3\",60,0,true,false),\n      chR(\"hh\",\"Chimbal\",\"#84cc16\",0,\"3-HH.mp3\",54,-14,true,false),\n      chR(\"tom1\",\"Tom 1\",\"#eab308\",0,\"4-TOM1.mp3\",52,-8,true,false),\n      chR(\"tom2\",\"Tom 2\",\"#22c55e\",0,\"5-TOM2.mp3\",52,8,true,false),\n      chR(\"sd\",\"Surdo\",\"#14b8a6\",0,\"6-SD.mp3\",62,-6,false,false),\n      chR(\"cg1\",\"Conga 1\",\"#06b6d4\",0,\"7-CG1.mp3\",54,-16,true,false),\n      chR(\"cg2\",\"Conga 2\",\"#3b82f6\",0,\"8-CG2.mp3\",54,16,true,false),\n      chR(\"bass\",\"Baixo\",\"#22c55e\",1,\"9-BASS.mp3\",64,0,false,true),\n      chR(\"gt\",\"Guitarra\",\"#14b8a6\",1,\"10-GT.mp3\",56,-20,true,false),\n      chR(\"ac\",\"Sanfona\",\"#f59e0b\",1,\"11-AC.mp3\",56,20,true,false),\n      chR(\"key\",\"Teclado\",\"#6366f1\",1,\"12-KEY.mp3\",54,-10,false,false),\n      chR(\"sax\",\"Sax\",\"#fbbf24\",1,\"13-SAX.mp3\",56,10,true,false),\n      chR(\"voz\",\"Voz\",\"#ec4899\",2,\"14-VOZ.mp3\",66,0,true,true),\n    ]},\n  };\n  const GKEYS=[\"pagodaoreal\",\"forroreal\",\"lambadareal\",\"avinehreal\",\"samvibereal\",\"vaneiraoreal\",\"forrorecordarreal\",\"rock\",\"samba\",\"pagode\",\"pagodao\"];\n  let genre=\"pagodaoreal\", CH=GEN[genre].ch(), DCA=GEN[genre].dca.map(d=>Object.assign({gain:80},d));\n  const FX={rev:{ret:70},dly:{ret:60,time:0.30,fb:0.32}};\n  const master={fader:80};\n  const by=id=>CH.find(c=>c.id===id);\n\n  // ---------------- WEB AUDIO ----------------\n  let ac=null,masterGain,masterAn,revConv,revRet,dly,dlyFb,dlyRet; let N={};\n  const faderToGain=f=>f<=1?0:dbToLin(-40+(f/100)*46);\n  function makeIR(sec){const rate=ac.sampleRate,len=Math.floor(rate*sec),b=ac.createBuffer(2,len,rate);for(let ch=0;ch<2;ch++){const d=b.getChannelData(ch);for(let i=0;i<len;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/len,2.5);}return b;}\n  function buildMaster(){\n    masterGain=ac.createGain();masterGain.gain.value=faderToGain(master.fader);\n    masterAn=ac.createAnalyser();masterAn.fftSize=256;\n    const lim=ac.createDynamicsCompressor();lim.threshold.value=-6;lim.ratio.value=12;lim.attack.value=0.003;lim.release.value=0.15;\n    masterGain.connect(lim);lim.connect(masterAn);lim.connect(ac.destination);\n    revConv=ac.createConvolver();revConv.buffer=makeIR(1.7);revRet=ac.createGain();revRet.gain.value=FX.rev.ret/100;revConv.connect(revRet);revRet.connect(masterGain);\n    dly=ac.createDelay(1.0);dly.delayTime.value=FX.dly.time;dlyFb=ac.createGain();dlyFb.gain.value=FX.dly.fb;dlyRet=ac.createGain();dlyRet.gain.value=FX.dly.ret/100;dly.connect(dlyFb);dlyFb.connect(dly);dly.connect(dlyRet);dlyRet.connect(masterGain);\n  }\n  function buildChannels(){\n    Object.values(N).forEach(n=>{try{n.trim.disconnect();n.fader.disconnect();n.pan.disconnect();}catch(e){}});\n    N={};\n    CH.forEach(c=>{\n      const trim=ac.createGain();trim.gain.value=dbToLin(c.gain);\n      const hpf=ac.createBiquadFilter();hpf.type=\"highpass\";hpf.frequency.value=c.eq.hpfOn?c.eq.hpf:20;\n      const low=ac.createBiquadFilter();low.type=\"lowshelf\";low.frequency.value=c.eq.low.f;low.gain.value=c.eq.low.g;\n      const lm=ac.createBiquadFilter();lm.type=\"peaking\";lm.frequency.value=c.eq.loMid.f;lm.Q.value=c.eq.loMid.q;lm.gain.value=c.eq.loMid.g;\n      const hm=ac.createBiquadFilter();hm.type=\"peaking\";hm.frequency.value=c.eq.hiMid.f;hm.Q.value=c.eq.hiMid.q;hm.gain.value=c.eq.hiMid.g;\n      const high=ac.createBiquadFilter();high.type=\"highshelf\";high.frequency.value=c.eq.high.f;high.gain.value=c.eq.high.g;\n      const cmp=ac.createDynamicsCompressor();setComp(cmp,c);\n      const fader=ac.createGain();fader.gain.value=0;\n      const pan=ac.createStereoPanner();pan.pan.value=c.pan/63;\n      const an=ac.createAnalyser();an.fftSize=256;\n      const sendR=ac.createGain();sendR.gain.value=c.rev/100;const sendD=ac.createGain();sendD.gain.value=c.dly/100;\n      trim.connect(hpf);hpf.connect(low);low.connect(lm);lm.connect(hm);hm.connect(high);high.connect(cmp);cmp.connect(fader);\n      fader.connect(pan);pan.connect(masterGain);fader.connect(an);fader.connect(sendR);sendR.connect(revConv);fader.connect(sendD);sendD.connect(dly);\n      N[c.id]={trim,hpf,low,lm,hm,high,cmp,fader,pan,an,sendR,sendD};\n    });\n    applyGains();\n  }\n  function setComp(cmp,c){cmp.threshold.value=c.cmp?c.compThr:0;cmp.ratio.value=c.cmp?3:1;cmp.attack.value=0.005;cmp.release.value=0.12;}\n  function applyGains(){if(!ac)return;const anySolo=CH.some(c=>c.solo);CH.forEach(c=>{const n=N[c.id];if(!n)return;const aud=anySolo?c.solo:!c.mute;n.fader.gain.setTargetAtTime(faderToGain(c.fader)*(DCA[c.dca].gain/80)*(aud?1:0),ac.currentTime,0.02);});}\n  function applyChannel(c){if(!ac)return;const n=N[c.id];if(!n)return;n.trim.gain.setTargetAtTime(dbToLin(c.gain),ac.currentTime,0.02);\n    n.hpf.frequency.value=c.eq.hpfOn?c.eq.hpf:20;n.low.frequency.value=c.eq.low.f;n.low.gain.value=c.eq.low.g;n.lm.frequency.value=c.eq.loMid.f;n.lm.gain.value=c.eq.loMid.g;\n    n.hm.frequency.value=c.eq.hiMid.f;n.hm.gain.value=c.eq.hiMid.g;n.high.frequency.value=c.eq.high.f;n.high.gain.value=c.eq.high.g;n.pan.pan.value=c.pan/63;setComp(n.cmp,c);n.sendR.gain.value=c.rev/100;n.sendD.gain.value=c.dly/100;}\n\n  // ---------- vozes por família ----------\n  function env(g,t,a,d,pk){g.gain.setValueAtTime(0.0001,t);g.gain.linearRampToValueAtTime(pk,t+a);g.gain.exponentialRampToValueAtTime(0.0008,t+a+d);}\n  function noise(dur){const n=Math.floor(ac.sampleRate*dur),b=ac.createBuffer(1,n,ac.sampleRate),d=b.getChannelData(0);for(let i=0;i<n;i++)d[i]=Math.random()*2-1;const s=ac.createBufferSource();s.buffer=b;return s;}\n  const ROOTS=[110,87.31,130.81,98];const triad=r=>[r,r*1.1892,r*1.4983];\n  function trigger(c,dest,t,bar){const p=c.p||{},g=ac.createGain();g.connect(dest);const root=ROOTS[bar%4];\n    switch(c.fam){\n      case\"drumlow\":{const o=ac.createOscillator();o.type=\"sine\";o.frequency.setValueAtTime(p.f||110,t);o.frequency.exponentialRampToValueAtTime(p.to||45,t+0.12);o.connect(g);env(g,t,0.002,0.2,1);o.start(t);o.stop(t+0.3);break;}\n      case\"drummid\":{const o=ac.createOscillator();o.type=\"triangle\";o.frequency.setValueAtTime(p.f||150,t);o.frequency.exponentialRampToValueAtTime((p.f||150)*0.6,t+0.12);o.connect(g);env(g,t,0.002,0.18,0.7);o.start(t);o.stop(t+0.25);break;}\n      case\"snare\":{const s=noise(0.2),bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=p.bp||1800;s.connect(bp);bp.connect(g);env(g,t,0.001,0.15,0.7);s.start(t);s.stop(t+0.2);break;}\n      case\"hat\":{const s=noise(0.05),hp=ac.createBiquadFilter();hp.type=\"highpass\";hp.frequency.value=p.hp||7000;s.connect(hp);hp.connect(g);env(g,t,0.001,0.04,0.32);s.start(t);s.stop(t+0.06);break;}\n      case\"cymbal\":{const s=noise(0.5),hp=ac.createBiquadFilter();hp.type=\"highpass\";hp.frequency.value=p.hp||5000;s.connect(hp);hp.connect(g);env(g,t,0.002,0.45,0.4);s.start(t);s.stop(t+0.5);break;}\n      case\"shaker\":{const s=noise(0.08),hp=ac.createBiquadFilter();hp.type=\"highpass\";hp.frequency.value=p.hp||3500;s.connect(hp);hp.connect(g);env(g,t,0.001,0.06,0.3);s.start(t);s.stop(t+0.09);break;}\n      case\"cuica\":{const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.setValueAtTime(300,t);o.frequency.linearRampToValueAtTime(600,t+0.12);o.frequency.linearRampToValueAtTime(320,t+0.24);const bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=500;bp.Q.value=6;o.connect(bp);bp.connect(g);env(g,t,0.01,0.22,0.4);o.start(t);o.stop(t+0.26);break;}\n      case\"bass\":{const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=root/2;const lp=ac.createBiquadFilter();lp.type=\"lowpass\";lp.frequency.value=500;o.connect(lp);lp.connect(g);env(g,t,0.004,0.28,0.6);o.start(t);o.stop(t+0.32);break;}\n      case\"pluck\":{triad(root).forEach(f=>{const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=f*(p.m||2);const lp=ac.createBiquadFilter();lp.type=\"lowpass\";lp.frequency.value=p.lp||2500;o.connect(lp);const gg=ac.createGain();lp.connect(gg);gg.connect(dest);env(gg,t,0.005,0.3,0.16);o.start(t);o.stop(t+0.35);});break;}\n      case\"pad\":{triad(root).forEach(f=>{const o=ac.createOscillator();o.type=\"triangle\";o.frequency.value=f*(p.m||2);o.detune.value=Math.random()*6-3;const gg=ac.createGain();o.connect(gg);gg.connect(dest);env(gg,t,0.05,1.6,0.13);o.start(t);o.stop(t+1.7);});break;}\n      case\"lead\":{ // VOZ: síntese de formantes (vogal \"ah\") + vibrato, registro de voz\n        const mel=[root*2,root*2.5,root*3,root*2.25];const base=mel[bar%4];\n        const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=base;\n        const lfo=ac.createOscillator();lfo.type=\"sine\";lfo.frequency.value=5.5;const lg=ac.createGain();lg.gain.value=base*0.013;lfo.connect(lg);lg.connect(o.frequency);lfo.start(t);lfo.stop(t+0.75);\n        const F=[[700,9,1],[1150,10,0.7],[2750,11,0.35]];const mix=ac.createGain();\n        F.forEach(([f,q,a])=>{const bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=f;bp.Q.value=q;const fg=ac.createGain();fg.gain.value=a;o.connect(bp);bp.connect(fg);fg.connect(mix);});\n        mix.connect(g);env(g,t,0.05,0.55,0.55);o.start(t);o.stop(t+0.65);break;}\n      case\"harm\":{ // CORO: formantes suaves em terça acima, mais velado\n        const base=root*2.5;const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=base;\n        const mix=ac.createGain();[[600,8,1],[1000,9,0.6]].forEach(([f,q,a])=>{const bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=f;bp.Q.value=q;const fg=ac.createGain();fg.gain.value=a;o.connect(bp);bp.connect(fg);fg.connect(mix);});\n        mix.connect(g);env(g,t,0.07,0.6,0.28);o.start(t);o.stop(t+0.7);break;}\n    }\n  }\n  let step=0,bar=0,nextTime=0,timer=null,playing=false;const BPM=100,stepDur=60/BPM/4;\n  function scheduler(){while(nextTime<ac.currentTime+0.12){CH.forEach(c=>{if(c.pat&&c.pat[step])trigger(c,N[c.id].trim,nextTime,bar);});step++;if(step>=16){step=0;bar++;}nextTime+=stepDur;}timer=setTimeout(scheduler,25);}\n  // ---------- ÁUDIO REAL (stems) ----------\n  const bufCache={}; let realSources=[];\n  async function loadBuf(url){ if(bufCache[url]) return bufCache[url]; const r=await fetch(url); if(!r.ok) throw new Error(\"HTTP \"+r.status); const ab=await r.arrayBuffer(); const b=await ac.decodeAudioData(ab); bufCache[url]=b; return b; }\n  async function playRealStart(){\n    const g=GEN[genre], base=SB+g.folder+\"/\";\n    $(\"play\").textContent=\"carregando áudio…\"; $(\"play\").disabled=true; $(\"srcTag\").textContent=\"baixando \"+CH.length+\" pistas…\";\n    try{\n      const bufs=await Promise.all(CH.map(c=>loadBuf(base+encodeURIComponent(c.url))));\n      const t0=ac.currentTime+0.12; realSources=[];\n      CH.forEach((c,i)=>{ const s=ac.createBufferSource(); s.buffer=bufs[i]; s.loop=true; s.connect(N[c.id].trim); s.start(t0); realSources.push(s); });\n      playing=true; $(\"play\").textContent=\"■ Parar\"; $(\"play\").classList.add(\"stop\"); $(\"srcTag\").textContent=\"áudio real: \"+g.label.replace(/🎵 /,\"\");\n    }catch(e){ $(\"srcTag\").textContent=\"erro ao carregar áudio\"; toast(\"Erro no áudio: \"+e.message); $(\"play\").textContent=\"▶ Tocar\"; }\n    $(\"play\").disabled=false;\n  }\n  function playRealStop(){ realSources.forEach(s=>{try{s.stop();}catch(e){}}); realSources=[]; playing=false; $(\"play\").textContent=\"▶ Tocar\"; $(\"play\").classList.remove(\"stop\"); }\n  $(\"play\").onclick=async()=>{if(ac.state===\"suspended\")await ac.resume();\n    if(GEN[genre].real){ if(!playing) playRealStart(); else playRealStop(); return; }\n    if(!playing){playing=true;$(\"play\").textContent=\"■ Parar\";$(\"play\").classList.add(\"stop\");step=0;bar=0;nextTime=ac.currentTime+0.06;scheduler();}\n    else{playing=false;$(\"play\").textContent=\"▶ Tocar\";$(\"play\").classList.remove(\"stop\");clearTimeout(timer);}};\n\n  // ---------- genre selector ----------\n  function renderGenres(){const g=$(\"genres\");g.innerHTML=\"\";GKEYS.forEach(k=>{const b=document.createElement(\"button\");b.className=\"gbtn\"+(k===genre?\" on\":\"\");b.textContent=GEN[k].label;b.onclick=()=>switchGenre(k);g.appendChild(b);});}\n  function switchGenre(k){if(k===genre)return;\n    if(playing){ if(GEN[genre].real)playRealStop(); else {playing=false;clearTimeout(timer);} $(\"play\").textContent=\"▶ Tocar\";$(\"play\").classList.remove(\"stop\"); }\n    genre=k;CH=GEN[k].ch();DCA=GEN[k].dca.map(d=>Object.assign({gain:80},d));selId=null;$(\"selpanel\").classList.remove(\"show\");\n    if(ac)buildChannels();renderGenres();render();mi=0;paintM();toast(\"Gênero: \"+GEN[k].label);}\n\n  // ---------- selected channel EQ ----------\n  let selId=null;const cv=$(\"eqcanvas\"),cx=cv.getContext(\"2d\");\n  const fx=f=>{const mn=Math.log10(20),mx=Math.log10(20000);return (Math.log10(f)-mn)/(mx-mn);};\n  const xf=(x,w)=>{const mn=Math.log10(20),mx=Math.log10(20000);return Math.pow(10,mn+(x/w)*(mx-mn));};\n  let handles=[];\n  // Redraw coalescing (iPad): dragging an EQ handle / gate / comp encoder fires many pointermove\n  // events; each drawEQ() reallocates and repaints the canvas. Doing that per event starves the\n  // main thread on iPad so controls lag. drawEQ() now coalesces to one repaint per animation frame\n  // (rAF), with a setTimeout safety-net in case requestAnimationFrame is throttled.\n  let _eqReq=0,_eqTo=0;\n  function _flushEQ(){ if(_eqReq){cancelAnimationFrame(_eqReq);_eqReq=0;} if(_eqTo){clearTimeout(_eqTo);_eqTo=0;} renderEQ(); }\n  function drawEQ(){ if(_eqReq||_eqTo)return; _eqReq=requestAnimationFrame(_flushEQ); _eqTo=setTimeout(_flushEQ,60); }\n  function renderEQ(){if(!selId)return;const c=by(selId),n=N[selId];if(!n)return;const rr=cv.getBoundingClientRect(),w=rr.width,h=rr.height;if(w<2)return;cv.width=w*2;cv.height=h*2;cx.setTransform(2,0,0,2,0,0);cx.clearRect(0,0,w,h);\n    cx.strokeStyle=\"#182339\";cx.fillStyle=\"#4a5a78\";cx.font=\"9px system-ui\";cx.textAlign=\"center\";[30,100,300,1000,3000,10000].forEach(f=>{const x=fx(f)*w;cx.beginPath();cx.moveTo(x,0);cx.lineTo(x,h);cx.stroke();cx.fillText(f>=1000?f/1000+\"k\":f,x,h-2);});\n    for(let d=-15;d<=15;d+=5){const y=h/2-d/18*h/2;cx.strokeStyle=d===0?\"#2a3a58\":\"#141e30\";cx.beginPath();cx.moveTo(0,y);cx.lineTo(w,y);cx.stroke();cx.fillStyle=\"#3a4a66\";cx.textAlign=\"left\";cx.fillText((d>0?\"+\":\"\")+d,2,y-2);}\n    const NP=160,freqs=new Float32Array(NP);for(let i=0;i<NP;i++)freqs[i]=xf((i/(NP-1))*w,w);const total=new Float32Array(NP).fill(1),mag=new Float32Array(NP),ph=new Float32Array(NP);\n    [n.hpf,n.low,n.lm,n.hm,n.high].forEach(b=>{b.getFrequencyResponse(freqs,mag,ph);for(let i=0;i<NP;i++)total[i]*=mag[i];});\n    cx.beginPath();for(let i=0;i<NP;i++){const x=(i/(NP-1))*w,db=20*Math.log10(total[i]||0.0001),y=h/2-clamp(db,-18,18)/18*h/2;i?cx.lineTo(x,y):cx.moveTo(x,y);}cx.strokeStyle=c.color;cx.lineWidth=2.4;cx.stroke();cx.lineTo(w,h/2);cx.lineTo(0,h/2);cx.closePath();cx.fillStyle=c.color+\"18\";cx.fill();\n    handles=[];const hpt=(f,gv,key,lbl,col)=>{const x=fx(f)*w,y=h/2-clamp(gv,-18,18)/18*h/2;cx.fillStyle=col;cx.beginPath();cx.arc(x,y,7,0,7);cx.fill();cx.fillStyle=\"#0b0f17\";cx.font=\"700 8px system-ui\";cx.textAlign=\"center\";cx.fillText(lbl,x,y+3);handles.push({x,y,key,w,h});};\n    if(c.eq.hpfOn)hpt(c.eq.hpf,-6,\"hpf\",\"H\",\"#f59e0b\");hpt(c.eq.low.f,c.eq.low.g,\"low\",\"L\",\"#22c55e\");hpt(c.eq.loMid.f,c.eq.loMid.g,\"loMid\",\"1\",\"#22d3ee\");hpt(c.eq.hiMid.f,c.eq.hiMid.g,\"hiMid\",\"2\",\"#3b82f6\");hpt(c.eq.high.f,c.eq.high.g,\"high\",\"H\",\"#a855f7\");}\n  let eqDrag=null;\n  const eqPos=e=>{const r=cv.getBoundingClientRect();return{x:(e.touches?e.touches[0].clientX:e.clientX)-r.left,y:(e.touches?e.touches[0].clientY:e.clientY)-r.top};};\n  cv.addEventListener(\"mousedown\",e=>eqDown(e));cv.addEventListener(\"touchstart\",e=>eqDown(e),{passive:false});\n  function eqDown(e){const p=eqPos(e);for(const h of handles){if(Math.hypot(p.x-h.x,p.y-h.y)<13){eqDrag=h;e.preventDefault();return;}}}\n  window.addEventListener(\"mousemove\",e=>eqMove(e));window.addEventListener(\"touchmove\",e=>eqMove(e),{passive:false});window.addEventListener(\"mouseup\",()=>eqDrag=null);window.addEventListener(\"touchend\",()=>eqDrag=null);\n  function eqMove(e){if(!eqDrag||!selId)return;const c=by(selId),p=eqPos(e);const f=clamp(xf(clamp(p.x,0,eqDrag.w),eqDrag.w),20,20000),g=clamp((eqDrag.h/2-p.y)/(eqDrag.h/2)*18,-15,15);\n    if(eqDrag.key===\"hpf\")c.eq.hpf=clamp(f,20,400);else if(eqDrag.key===\"low\"){c.eq.low.f=clamp(f,40,400);c.eq.low.g=g;}else if(eqDrag.key===\"loMid\"){c.eq.loMid.f=clamp(f,100,2000);c.eq.loMid.g=g;}else if(eqDrag.key===\"hiMid\"){c.eq.hiMid.f=clamp(f,800,8000);c.eq.hiMid.g=g;}else if(eqDrag.key===\"high\"){c.eq.high.f=clamp(f,2000,16000);c.eq.high.g=g;}\n    applyChannel(c);drawEQ();syncStripKnobs(c);check();e.preventDefault();}\n  function openSel(id){selId=id;const c=by(id);$(\"selpanel\").classList.add(\"show\");$(\"selChip\").style.background=c.color;$(\"selName\").textContent=c.nm;\n    $(\"tHpf\").classList.toggle(\"on\",c.eq.hpfOn);$(\"tHpf\").classList.toggle(\"amber\",c.eq.hpfOn);$(\"tGate\").classList.toggle(\"on\",c.gateOn);$(\"tComp\").classList.toggle(\"on\",c.cmp);\n    $(\"sGain\").value=c.gain;$(\"vGain\").textContent=c.gain+\" dB\";$(\"sGate\").value=c.gateThr;$(\"vGate\").textContent=c.gateThr;$(\"sComp\").value=c.compThr;$(\"vComp\").textContent=c.compThr;$(\"sRev\").value=c.rev;$(\"vRev\").textContent=c.rev;$(\"sDly\").value=c.dly;$(\"vDly\").textContent=c.dly;\n    CH.forEach(x=>{const s=document.querySelector(''.strip[data-id=\"''+x.id+''\"]'');if(s)s.classList.toggle(\"sel\",x.id===id);});drawEQ();}\n  $(\"selClose\").onclick=()=>{$(\"selpanel\").classList.remove(\"show\");selId=null;CH.forEach(x=>{const s=document.querySelector(''.strip[data-id=\"''+x.id+''\"]'');if(s)s.classList.remove(\"sel\");});};\n  $(\"tHpf\").onclick=()=>{const c=by(selId);c.eq.hpfOn=!c.eq.hpfOn;$(\"tHpf\").classList.toggle(\"on\",c.eq.hpfOn);$(\"tHpf\").classList.toggle(\"amber\",c.eq.hpfOn);applyChannel(c);drawEQ();check();};\n  $(\"tGate\").onclick=()=>{const c=by(selId);c.gateOn=!c.gateOn;$(\"tGate\").classList.toggle(\"on\",c.gateOn);check();};\n  $(\"tComp\").onclick=()=>{const c=by(selId);c.cmp=!c.cmp;$(\"tComp\").classList.toggle(\"on\",c.cmp);applyChannel(c);syncStripKnobs(c);check();};\n  const bindR=(idr,idv,set,suf)=>{$(idr).oninput=()=>{const c=by(selId);set(c,+$(idr).value);$(idv).textContent=$(idr).value+(suf||\"\");applyChannel(c);syncStripKnobs(c);check();};};\n  bindR(\"sGain\",\"vGain\",(c,v)=>c.gain=v,\" dB\");bindR(\"sGate\",\"vGate\",(c,v)=>c.gateThr=v);bindR(\"sComp\",\"vComp\",(c,v)=>c.compThr=v);bindR(\"sRev\",\"vRev\",(c,v)=>c.rev=v);bindR(\"sDly\",\"vDly\",(c,v)=>c.dly=v);\n\n  // ---------- board ----------\n  const KN={gain:{min:-12,max:24},hi:{min:-15,max:15},mid:{min:-15,max:15},lo:{min:-15,max:15},pan:{min:-63,max:63},fx:{min:0,max:100}};\n  const rotOf=(k,v)=>{const d=KN[k];return -140+(v-d.min)/(d.max-d.min)*280;};\n  const board=$(\"board\");\n  const quickVal=(c,k)=>({gain:c.gain,hi:c.eq.high.g,mid:c.eq.hiMid.g,lo:c.eq.low.g,pan:c.pan,fx:c.rev})[k];\n  function quickSet(c,k,v){if(k===\"gain\")c.gain=v;else if(k===\"hi\")c.eq.high.g=v;else if(k===\"mid\")c.eq.hiMid.g=v;else if(k===\"lo\")c.eq.low.g=v;else if(k===\"pan\")c.pan=v;else if(k===\"fx\")c.rev=v;}\n  function syncStripKnobs(c){[\"gain\",\"hi\",\"mid\",\"lo\",\"pan\",\"fx\"].forEach(k=>{const el=board.querySelector(''.dial[data-ch=\"''+c.id+''\"][data-k=\"''+k+''\"]'');if(el)el.style.setProperty(\"--rot\",rotOf(k,quickVal(c,k))+\"deg\");});}\n  const knob=(c,k,cls)=>`<div class=\"knob\"><div class=\"dial ${cls||''''}\" data-ch=\"${c.id}\" data-k=\"${k}\"></div><div class=\"kl\">${({gain:\"GAIN\",hi:\"HI\",mid:\"MID\",lo:\"LO\",pan:\"PAN\",fx:\"REV\"})[k]}</div></div>`;\n  function stripEl(c){const d=document.createElement(\"div\");d.className=\"strip\";d.dataset.id=c.id;\n    d.innerHTML=`<div class=\"cname\" style=\"background:${c.color}\">${c.nm}</div>${knob(c,\"gain\",\"g\")}<div class=\"rowk\">${knob(c,\"hi\",\"eq\")}${knob(c,\"mid\",\"eq\")}${knob(c,\"lo\",\"eq\")}</div><div class=\"rowk\">${knob(c,\"pan\")}${knob(c,\"fx\",\"fx\")}</div>\n      <button class=\"mini sel\" data-sel=\"${c.id}\">SEL ▸ EQ</button>\n      <div class=\"faderwrap\"><div class=\"meter\"><i id=\"m-${c.id}\"></i></div><div class=\"fader\" data-f=\"${c.id}\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-${c.id}\"></div></div></div>\n      <div class=\"fdb\" id=\"fdb-${c.id}\">${c.fader}</div>\n      <div class=\"btnrow\"><button class=\"sb solo ${c.solo?''on'':''''}\" data-solo=\"${c.id}\">S</button><button class=\"sb mute ${c.mute?''on'':''''}\" data-mute=\"${c.id}\">M</button></div>\n      <div class=\"assign\">DCA ${DCA[c.dca].nm}</div>`;return d;}\n  function fxEl(){const d=document.createElement(\"div\");d.className=\"strip fx\";d.innerHTML=`<div class=\"cname\" style=\"background:#a855f7\">FX RACK</div><div class=\"assign\">Reverb / Delay</div>\n    <div style=\"font-size:8px;color:var(--muted)\">REVERB</div><div class=\"faderwrap\"><div class=\"fader\" data-fx=\"rev\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-fxrev\"></div></div></div><div class=\"fdb\" id=\"fdb-fxrev\">${FX.rev.ret}</div>\n    <div style=\"font-size:8px;color:var(--muted)\">DELAY</div><div class=\"faderwrap\"><div class=\"fader\" data-fx=\"dly\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-fxdly\"></div></div></div><div class=\"fdb\" id=\"fdb-fxdly\">${FX.dly.ret}</div>`;return d;}\n  function dcaEl(d0,i){const el=document.createElement(\"div\");el.className=\"strip dca\";el.innerHTML=`<div class=\"cname\" style=\"background:${d0.color}\">${d0.nm}</div><div class=\"assign\">GRUPO/DCA</div><div style=\"flex:1\"></div><div class=\"faderwrap\"><div class=\"fader\" data-dca=\"${i}\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-dca${i}\"></div></div></div><div class=\"fdb\" id=\"fdb-dca${i}\">${d0.gain}</div>`;return el;}\n  function masterEl(){const el=document.createElement(\"div\");el.className=\"strip master\";el.innerHTML=`<div class=\"cname\" style=\"background:var(--amber)\">MASTER</div><div class=\"assign\">saída L/R</div><div style=\"flex:1\"></div><div class=\"faderwrap\"><div class=\"meter\"><i id=\"m-main\"></i></div><div class=\"fader\" data-master=\"1\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-main\"></div></div></div><div class=\"fdb\" id=\"fdb-main\">${master.fader}</div>`;return el;}\n  function render(){board.innerHTML=\"\";CH.forEach(c=>board.appendChild(stripEl(c)));board.appendChild(fxEl());DCA.forEach((d,i)=>board.appendChild(dcaEl(d,i)));board.appendChild(masterEl());placeCaps();}\n  function placeCaps(){CH.forEach(c=>{const cap=$(\"cap-\"+c.id);if(cap)cap.style.bottom=\"calc(\"+c.fader+\"% - 8px)\";syncStripKnobs(c);});DCA.forEach((d,i)=>{const cap=$(\"cap-dca\"+i);if(cap)cap.style.bottom=\"calc(\"+d.gain+\"% - 8px)\";});[\"rev\",\"dly\"].forEach(k=>{const cap=$(\"cap-fx\"+k);if(cap)cap.style.bottom=\"calc(\"+FX[k].ret+\"% - 8px)\";});const cm=$(\"cap-main\");if(cm)cm.style.bottom=\"calc(\"+master.fader+\"% - 8px)\";}\n  // Interação unificada (mouse + toque) por Pointer Events + delegação no board.\n  // Registrada UMA vez (setupBoard) — render() só reconstrói o visual, sem re-registrar listeners.\n  let knobDrag=null,faderDrag=null,lastY=0;\n  function faderSet(f,clientY){const r=f.getBoundingClientRect(),v=Math.round(clamp(1-(clientY-r.top)/r.height,0,1)*100);\n    if(f.dataset.f){const c=by(f.dataset.f);c.fader=v;$(\"fdb-\"+c.id).textContent=v;$(\"cap-\"+c.id).style.bottom=\"calc(\"+v+\"% - 8px)\";applyGains();}\n    else if(f.dataset.dca!==undefined){const i=+f.dataset.dca;DCA[i].gain=v;$(\"fdb-dca\"+i).textContent=v;$(\"cap-dca\"+i).style.bottom=\"calc(\"+v+\"% - 8px)\";applyGains();}\n    else if(f.dataset.fx){const k=f.dataset.fx;FX[k].ret=v;$(\"fdb-fx\"+k).textContent=v;$(\"cap-fx\"+k).style.bottom=\"calc(\"+v+\"% - 8px)\";if(ac)(k===\"rev\"?revRet:dlyRet).gain.value=v/100;}\n    else{master.fader=v;$(\"fdb-main\").textContent=v;$(\"cap-main\").style.bottom=\"calc(\"+v+\"% - 8px)\";if(ac)masterGain.gain.setTargetAtTime(faderToGain(v),ac.currentTime,0.02);}check();}\n  function setupBoard(){\n    board.addEventListener(\"pointerdown\",e=>{\n      const dial=e.target.closest(\".dial\");\n      if(dial){knobDrag={el:dial,chid:dial.dataset.ch,k:dial.dataset.k};lastY=e.clientY;board.setPointerCapture(e.pointerId);e.preventDefault();return;}\n      const f=e.target.closest(\".fader\");\n      if(f){faderDrag=f;board.setPointerCapture(e.pointerId);faderSet(f,e.clientY);e.preventDefault();return;}\n    });\n    board.addEventListener(\"pointermove\",e=>{\n      if(knobDrag){const dy=lastY-e.clientY;lastY=e.clientY;const c=by(knobDrag.chid),d=KN[knobDrag.k];if(!c)return;\n        quickSet(c,knobDrag.k,clamp(quickVal(c,knobDrag.k)+dy*(d.max-d.min)/150,d.min,d.max));\n        knobDrag.el.style.setProperty(\"--rot\",rotOf(knobDrag.k,quickVal(c,knobDrag.k))+\"deg\");applyChannel(c);if(selId===knobDrag.chid)drawEQ();check();e.preventDefault();}\n      else if(faderDrag){faderSet(faderDrag,e.clientY);e.preventDefault();}\n    });\n    const end=()=>{knobDrag=null;faderDrag=null;};\n    board.addEventListener(\"pointerup\",end);board.addEventListener(\"pointercancel\",end);\n    board.addEventListener(\"click\",e=>{\n      const s=e.target.closest(\"[data-sel]\");if(s){openSel(s.dataset.sel);return;}\n      const so=e.target.closest(\"[data-solo]\");if(so){const c=by(so.dataset.solo);c.solo=!c.solo;so.classList.toggle(\"on\",c.solo);applyGains();check();return;}\n      const mu=e.target.closest(\"[data-mute]\");if(mu){const c=by(mu.dataset.mute);c.mute=!c.mute;mu.classList.toggle(\"on\",c.mute);applyGains();check();return;}\n    });\n  }\n  function rms(an){if(!an)return 0;const a=new Uint8Array(an.fftSize);an.getByteTimeDomainData(a);let s=0;for(let i=0;i<a.length;i++){const v=(a[i]-128)/128;s+=v*v;}return Math.sqrt(s/a.length);}\n  function loop(){if(ac){CH.forEach(c=>{const el=$(\"m-\"+c.id);if(el&&N[c.id])el.style.height=clamp(rms(N[c.id].an)*180,0,100)+\"%\";});const mel=$(\"m-main\"),mb=$(\"mainMeter\"),mr=rms(masterAn);if(mel)mel.style.height=clamp(mr*180,0,100)+\"%\";if(mb)mb.style.width=clamp(mr*180,0,100)+\"%\";}requestAnimationFrame(loop);}\n\n  const bassCh=()=>by(\"bass\")||by(\"baixo\")||by(\"violao7\");\n  const M=[\n    {t:''Dê o play e <b>equilibre a base</b>: deixe o <b>1º fader</b> (bumbo/surdo) forte (~75+) e o <b>baixo</b> firme.'',ok:()=>CH[0].fader>=72&&bassCh()&&bassCh().fader>=68},\n    {t:''Trabalhe o <b>EQ</b>: abra o <b>SEL</b> de um canal, ligue o <b>HPF</b> e dê <b>brilho</b> (banda High acima de +3).'',ok:()=>CH.some(c=>c.eq.hpfOn&&c.eq.high.g>=3)},\n    {t:''<b>Efeito</b>: mande algum canal para o <b>Reverb</b> (knob REV ou fader Reverb no SEL acima de 30).'',ok:()=>CH.some(c=>c.rev>=30)},\n    {t:''<b>Panorama</b>: espalhe instrumentos nos lados (pan de algum canal &gt; 30 para cada lado).'',ok:()=>CH.some(c=>Math.abs(c.pan)>=30)},\n    {t:''<b>Grupo</b>: baixe o <b>1º DCA</b> abaixo de 70 e veja o grupo descer junto.'',ok:()=>DCA[0].gain<70},\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");if(mi>=M.length){idx.textContent=\"🎓\";txt.innerHTML=\"<b>Mix completa!</b> Gain, EQ paramétrico, efeitos, grupos e panorama — a experiência completa do console, em \"+GEN[genre].label+\".\";$(\"mSkip\").style.display=\"none\";return;}idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;toast(mi>=M.length?\"Mix completa! 🎓\":\"Boa! ✔\");paintM();}}catch(e){}}\n  let tt;function toast(m){const el=$(\"toast\");el.innerHTML=m;el.classList.add(\"show\");clearTimeout(tt);tt=setTimeout(()=>el.classList.remove(\"show\"),1500);}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  ac=new (window.AudioContext||window.webkitAudioContext)();buildMaster();buildChannels();\n  setupBoard();renderGenres();render();paintM();requestAnimationFrame(loop);\n\n  // ---- FIT: escala a mesa inteira para caber na tela (sem scroll horizontal no desktop/tablet) ----\n  function fitConsole(){\n    const el=document.querySelector(\".fit\"); if(!el) return;\n    const IW=window.innerWidth, IH=window.innerHeight;\n    if(IW<760){ el.style.width=\"100%\"; el.style.zoom=\"\"; document.body.style.justifyContent=\"flex-start\"; }\n    else{\n      el.style.width=\"max-content\"; el.style.zoom=\"\";\n      const DW=el.offsetWidth, DH=el.offsetHeight;\n      // Em fullscreen o iframe 16:9 do player fica MAIS ALTO que a tela real. Usamos screen.height\n      // (altura real), não window.innerHeight (altura inflada do iframe), e alinhamos ao topo.\n      const scrH=(window.screen&&screen.height)||IH;\n      const iframeTaller=IH>scrH+8;\n      const visH=Math.min(IH,scrH);\n      const headerAllow=iframeTaller?84:(IH>700?40:6);\n      const effVh=Math.max(240, visH-headerAllow);\n      document.body.style.justifyContent=(iframeTaller||IH>700)?\"flex-start\":\"center\";\n      let s=Math.min((IW-18)/DW, effVh/DH); s=Math.max(0.35, Math.min(s, 2.2));\n      el.style.zoom=s;\n    }\n    try{ drawEQ(); }catch(e){}\n  }\n  window.addEventListener(\"resize\", fitConsole);\n  setTimeout(fitConsole, 50);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);
